import React from 'react';
import LogementCarrousel from '../components/LogementCarrousel';
import LogementHeader from '../components/LogementHeader';
import LogementHost from '../components/LogementHost';

function Logement() {
    return (
        <>
            <LogementCarrousel />
            <LogementHeader />
            <LogementHost />

            <div className="logement__description">
                <p>Description</p>
                <p>text_1</p>
            </div>

            <div className="logement__equipements">
                <p>Equipements</p>
                <p>text_2</p>
            </div>
        </>
    );
}

export default Logement;
